import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {
    public static void main(String[] args) {
        try {
            System.out.print("Enter the IP address to ping: ");
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            String ip = reader.readLine();

            // Build the command with proper arguments using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder("ping", ip);

            // Start the process
            Process process = processBuilder.start();

            BufferedReader resultReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = resultReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Command Injection
